const calculateQuotePremium = (items: any[]): { premium: number } => {
  const componentCounts: Record<string, number> = {};
  let itemsCost = 0;

  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
    } else {
      const base = BASE_PREMIUMS[item.type] || 0;
      let itemPremium = base;
      if (item.cursed) {
        itemPremium += base * 0.5;
      }
      if (item.enchantment >= 5) {
        itemPremium += base * 0.3;
      }
      itemsCost += itemPremium;
    }
  }

  for (const count of Object.values(componentCounts)) {
    if (count === BLOCK_SIZE) {
      itemsCost += BLOCK_PREMIUM;
    } else {
      itemsCost += count * COMPONENT_PREMIUM;
    }
  }

  return { premium: itemsCost + PROCESSING_FEE };
};

